import os
import json
import logging
import uuid
from datetime import datetime

import azure.functions as func
from azure.identity import DefaultAzureCredential
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient
from azure.eventgrid import EventGridPublisherClient
from azure.core.messaging import CloudEvent


# Configuration from environment variables
STORAGE_ACCOUNT_URL = os.environ.get("STORAGE_ACCOUNT_URL", "https://<storage-account>.blob.core.windows.net")
COSMOS_ENDPOINT = os.environ.get("COSMOS_ENDPOINT", "https://<cosmos-account>.documents.azure.com:443/")
COSMOS_DATABASE_NAME = os.environ.get("COSMOS_DATABASE_NAME", "processingdb")
COSMOS_CONTAINER_NAME = os.environ.get("COSMOS_CONTAINER_NAME", "results")
EVENTGRID_ENDPOINT = os.environ.get("EVENTGRID_ENDPOINT", "https://<topic-name>.<region>.eventgrid.azure.net/api/events")
SOURCE_CONTAINER = os.environ.get("SOURCE_CONTAINER", "incoming-files")
PROCESSED_CONTAINER = os.environ.get("PROCESSED_CONTAINER", "processed-files")

# Initialize the Azure Function App
app = func.FunctionApp()

# --- Credential & Client Management ---
# Use Managed Identity (DefaultAzureCredential) for all Azure service access.
# Required RBAC role assignments on the Function App's Managed Identity:
#   - Storage Blob Data Contributor on the Storage Account
#   - Cosmos DB Account Contributor (or built-in data plane role) on Cosmos DB
#   - Event Grid Data Sender on the Event Grid Topic
#
# SECURITY NOTE FOR PRODUCTION:
#   - Apply least-privilege: scope roles to specific resources, not resource groups.
#   - Consider using Cosmos DB built-in data plane RBAC roles
#     (e.g., "Cosmos DB Built-in Data Contributor") instead of control-plane roles.
#   - Rotate credentials and review access regularly.
#   - Use separate managed identities per function if functions have different access needs.


def get_credential():
    """Get Azure credential using Managed Identity (or local dev credentials)."""
    return DefaultAzureCredential()


def get_blob_service_client():
    """Create BlobServiceClient using Managed Identity."""
    credential = get_credential()
    return BlobServiceClient(account_url=STORAGE_ACCOUNT_URL, credential=credential)


def get_cosmos_client():
    """Create CosmosClient using Managed Identity (AAD-based auth)."""
    credential = get_credential()
    return CosmosClient(url=COSMOS_ENDPOINT, credential=credential)


def get_eventgrid_client():
    """Create EventGridPublisherClient using Managed Identity."""
    credential = get_credential()
    return EventGridPublisherClient(endpoint=EVENTGRID_ENDPOINT, credential=credential)


# --- File Processing Logic ---

def process_file_content(blob_name: str, content: bytes) -> dict:
    """
    Process the file content and return structured results.
    Replace this with your actual business logic.
    """
    try:
        # Example: parse JSON content
        if blob_name.endswith(".json"):
            data = json.loads(content.decode("utf-8"))
            record_count = len(data) if isinstance(data, list) else 1
        elif blob_name.endswith(".csv"):
            lines = content.decode("utf-8").strip().split("\n")
            record_count = len(lines) - 1  # Exclude header
            data = {"lines": record_count, "header": lines[0] if lines else ""}
        else:
            # Generic binary file processing
            data = {"size_bytes": len(content)}
            record_count = 1

        return {
            "status": "success",
            "record_count": record_count,
            "summary": data,
            "file_size_bytes": len(content),
        }
    except Exception as e:
        logging.error(f"Error processing file {blob_name}: {str(e)}")
        return {
            "status": "error",
            "error_message": str(e),
            "file_size_bytes": len(content),
        }


def write_result_to_cosmos(result: dict) -> dict:
    """Write processing result to Cosmos DB."""
    cosmos_client = get_cosmos_client()
    database = cosmos_client.get_database_client(COSMOS_DATABASE_NAME)
    container = database.get_container_client(COSMOS_CONTAINER_NAME)

    # Cosmos DB document
    document = {
        "id": result.get("id", str(uuid.uuid4())),
        "partitionKey": result.get("partition_key", "default"),
        "blobName": result.get("blob_name"),
        "containerName": result.get("container_name"),
        "processedAt": result.get("processed_at"),
        "processingResult": result.get("processing_result"),
        "functionInvocationId": result.get("invocation_id"),
        "ttl": -1,  # No expiration; set to seconds for auto-cleanup
    }

    created_document = container.upsert_item(body=document)
    logging.info(f"Document written to Cosmos DB: {created_document['id']}")
    return created_document


def send_eventgrid_notification(event_data: dict):
    """Send a notification via Event Grid."""
    client = get_eventgrid_client()

    event = CloudEvent(
        source=f"/azure/functions/file-processor",
        type="FileProcessing.Completed",
        data={
            "blob_name": event_data.get("blob_name"),
            "container_name": event_data.get("container_name"),
            "status": event_data.get("status"),
            "cosmos_document_id": event_data.get("cosmos_document_id"),
            "processed_at": event_data.get("processed_at"),
            "record_count": event_data.get("record_count", 0),
        },
        subject=f"files/{event_data.get('blob_name', 'unknown')}",
    )

    client.send([event])
    logging.info(f"Event Grid notification sent for blob: {event_data.get('blob_name')}")


def move_blob_to_processed(blob_service_client, source_container: str, blob_name: str):
    """Move processed blob from source to processed container."""
    try:
        source_blob = blob_service_client.get_blob_client(
            container=source_container, blob=blob_name
        )
        dest_blob = blob_service_client.get_blob_client(
            container=PROCESSED_CONTAINER, blob=blob_name
        )

        # Copy source to destination
        dest_blob.start_copy_from_url(source_blob.url)

        # Delete from source
        source_blob.delete_blob()
        logging.info(f"Blob moved from {source_container}/{blob_name} to {PROCESSED_CONTAINER}/{blob_name}")
    except Exception as e:
        logging.warning(f"Could not move blob {blob_name}: {str(e)}")


# --- Azure Function Triggers ---

@app.blob_trigger(
    arg_name="myblob",
    path=f"{SOURCE_CONTAINER}/{{name}}",
    connection="AzureWebJobsStorage",
)
def blob_trigger_processor(myblob: func.InputStream):
    """
    Blob-triggered function: automatically processes files uploaded to the source container.
    """
    logging.info(
        f"Blob trigger fired - Name: {myblob.name}, Size: {myblob.length} bytes"
    )

    blob_name = myblob.name.split("/", 1)[-1] if "/" in myblob.name else myblob.name
    invocation_id = str(uuid.uuid4())
    processed_at = datetime.utcnow().isoformat() + "Z"

    try:
        # Step 1: Read and process file content
        content = myblob.read()
        processing_result = process_file_content(blob_name, content)
        logging.info(f"Processing result for {blob_name}: {processing_result['status']}")

        # Step 2: Write results to Cosmos DB
        cosmos_result = write_result_to_cosmos({
            "id": invocation_id,
            "partition_key": processed_at[:10],  # Date-based partitioning
            "blob_name": blob_name,
            "container_name": SOURCE_CONTAINER,
            "processed_at": processed_at,
            "processing_result": processing_result,
            "invocation_id": invocation_id,
        })

        # Step 3: Send Event Grid notification
        send_eventgrid_notification({
            "blob_name": blob_name,
            "container_name": SOURCE_CONTAINER,
            "status": processing_result["status"],
            "cosmos_document_id": cosmos_result["id"],
            "processed_at": processed_at,
            "record_count": processing_result.get("record_count", 0),
        })

        # Step 4: Move blob to processed container
        blob_service_client = get_blob_service_client()
        move_blob_to_processed(blob_service_client, SOURCE_CONTAINER, blob_name)

        logging.info(f"Successfully processed blob: {blob_name}")

    except Exception as e:
        logging.error(f"Failed to process blob {blob_name}: {str(e)}")
        # Send failure notification
        try:
            send_eventgrid_notification({
                "blob_name": blob_name,
                "container_name": SOURCE_CONTAINER,
                "status": "error",
                "cosmos_document_id": None,
                "processed_at": processed_at,
                "error": str(e),
            })
        except Exception as notify_err:
            logging.error(f"Failed to send error notification: {str(notify_err)}")
        raise


@app.route(route="process/{container_name}/{blob_name}", methods=["POST"], auth_level=func.AuthLevel.FUNCTION)
def http_trigger_processor(req: func.HttpRequest) -> func.HttpResponse:
    """
    HTTP-triggered function: manually trigger processing of a specific blob.
    Useful for reprocessing or on-demand processing.
    """
    container_name = req.route_params.get("container_name", SOURCE_CONTAINER)
    blob_name = req.route_params.get("blob_name")

    if not blob_name:
        return func.HttpResponse(
            json.dumps({"error": "blob_name is required"}),
            status_code=400,
            mimetype="application/json",
        )

    invocation_id = str(uuid.uuid4())
    processed_at = datetime.utcnow().isoformat() + "Z"

    try:
        # Step 1: Download blob from storage
        blob_service_client = get_blob_service_client()
        blob_client = blob_service_client.get_blob_client(
            container=container_name, blob=blob_name
        )
        content = blob_client.download_blob().readall()
        logging.info(f"Downloaded blob {container_name}/{blob_name}, size: {len(content)} bytes")

        # Step 2: Process file content
        processing_result = process_file_content(blob_name, content)

        # Step 3: Write results to Cosmos DB
        cosmos_result = write_result_to_cosmos({
            "id": invocation_id,
            "partition_key": processed_at[:10],
            "blob_name": blob_name,
            "container_name": container_name,
            "processed_at": processed_at,
            "processing_result": processing_result,
            "invocation_id": invocation_id,
        })

        # Step 4: Send Event Grid notification
        send_eventgrid_notification({
            "blob_name": blob_name,
            "container_name": container_name,
            "status": processing_result["status"],
            "cosmos_document_id": cosmos_result["id"],
            "processed_at": processed_at,
            "record_count": processing_result.get("record_count", 0),
        })

        response_body = {
            "message": "File processed successfully",
            "invocation_id": invocation_id,
            "cosmos_document_id": cosmos_result["id"],
            "processing_result": processing_result,
            "processed_at": processed_at,
        }
        return func.HttpResponse(
            json.dumps(response_body),
            status_code=200,
            mimetype="application/json",
        )

    except Exception as e:
        logging.error(f"HTTP trigger processing failed for {blob_name}: {str(e)}")
        error_response = {
            "error": str(e),
            "blob_name": blob_name,
            "container_name": container_name,
            "invocation_id": invocation_id,
        }
        return func.HttpResponse(
            json.dumps(error_response),
            status_code=500,
            mimetype="application/json",
        )


@app.route(route="health", methods=["GET"], auth_level=func.AuthLevel.ANONYMOUS)
def health_check(req: func.HttpRequest) -> func.HttpResponse:
    """Health check endpoint that verifies connectivity to all dependent services."""
    health_status = {
        "function": "healthy",
        "timestamp": datetime.utcnow().isoformat() + "Z",
        "services": {},
    }

    # Check Blob Storage
    try:
        blob_service_client = get_blob_service_client()
        containers = list(blob_service_client.list_containers(results_per_page=1))
        health_status["services"]["blob_storage"] = "healthy"
    except Exception as e:
        health_status["services"]["blob_storage"] = f"unhealthy: {str(e)}"

    # Check Cosmos DB
    try:
        cosmos_client = get_cosmos_client()
        database = cosmos_client.get_database_client(COSMOS_DATABASE_NAME)
        database.read()
        health_status["services"]["cosmos_db"] = "healthy"
    except Exception as e:
        health_status["services"]["cosmos_db"] = f"unhealthy: {str(e)}"

    # Check Event Grid
    try:
        eg_client = get_eventgrid_client()
        # EventGrid client doesn't have a simple ping; we just verify client creation
        health_status["services"]["event_grid"] = "client_initialized"
    except Exception as e:
        health_status["services"]["event_grid"] = f"unhealthy: {str(e)}"

    all_healthy = all(
        "unhealthy" not in v
        for v in health_status["services"].values()
    )
    status_code = 200 if all_healthy else 503

    return func.HttpResponse(
        json.dumps(health_status, indent=2),
        status_code=status_code,
        mimetype="application/json",
    )


@app.route(route="list-blobs/{container_name}", methods=["GET"], auth_level=func.AuthLevel.FUNCTION)
def list_blobs(req: func.HttpRequest) -> func.HttpResponse:
    """List blobs in a container - useful for checking pending files."""
    container_name = req.route_params.get("container_name", SOURCE_CONTAINER)
    max_results = int(req.params.get("max_results", "50"))

    try:
        blob_service_client = get_blob_service_client()
        container_client = blob_service_client.get_container_client(container_name)

        blobs = []
        for blob in container_client.list_blobs(results_per_page=max_results):
            blobs.append({
                "name": blob.name,
                "size": blob.size,
                "last_modified": blob.last_modified.isoformat() if blob.last_modified else None,
                "content_type": blob.content_settings.content_type if blob.content_settings else None,
            })
            if len(blobs) >= max_results:
                break

        return func.HttpResponse(
            json.dumps({
                "container": container_name,
                "count": len(blobs),
                "blobs": blobs,
            }, indent=2),
            status_code=200,
            mimetype="application/json",
        )
    except Exception as e:
        return func.HttpResponse(
            json.dumps({"error": str(e)}),
            status_code=500,
            mimetype="application/json",
        )